#include "qp/backtest/metrics.hpp"
#include <algorithm>
#include <cmath>
namespace qp::backtest { Result<BacktestMetrics> compute_metrics(const BacktestReport& r){ if(r.initial_cash<=0.0) return Err<BacktestMetrics>(Error{ErrorCode::InvalidArgument,"initial cash must be positive"}); BacktestMetrics m; m.total_return=r.final_equity/r.initial_cash-1.0; m.trades=r.fills.size(); double peak=r.initial_cash; for(const auto& p:r.equity_curve){ peak=std::max(peak,p.equity); double dd=peak-p.equity; if(dd>m.max_drawdown){ m.max_drawdown=dd; m.max_drawdown_pct=peak>0.0?dd/peak:0.0; } } double gains=0.0, losses=0.0; std::size_t breakeven_trades=0; for(const auto& e:r.ledger){ m.total_commission += e.fill.commission; m.total_slippage += e.fill.slippage; if(e.realized_pnl>0){ ++m.winning_trades; gains += e.realized_pnl; } if(e.realized_pnl<0){ ++m.losing_trades; losses += -e.realized_pnl; } if(e.fill.side==execution::OrderSide::Sell && e.realized_pnl==0.0){ ++breakeven_trades; } } auto closed=m.winning_trades+m.losing_trades+breakeven_trades; m.win_rate=closed?static_cast<double>(m.winning_trades)/static_cast<double>(closed):0.0; m.profit_factor=losses>0.0?gains/losses:(gains>0.0?std::numeric_limits<double>::infinity():0.0); return Ok(m); } }
